### 3. Protocol Buffers의 Chat 관련 .proto 파일

**`/protobuf/` 모듈 구조** (grpc-skill 기반)

```
protobuf/
└── src/main/proto/
    └── chat/
        ├── chat_message.proto
        ├── chat_room.proto
        └── chat_service.proto
```

**예상 Proto 정의** (grpc-skill 가이드 기반):

```protobuf
// protobuf/src/main/proto/chat/chat_service.proto
syntax = "proto3";
package chat;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.chat";

service ChatService {
  rpc GetChatRoom(GetChatRoomRequest) returns (GetChatRoomResponse);
  rpc ListChatRooms(ListChatRoomsRequest) returns (ListChatRoomsResponse);
  rpc CreateChatRoom(CreateChatRoomRequest) returns (CreateChatRoomResponse);
  rpc SendMessage(SendMessageRequest) returns (SendMessageResponse);
  rpc GetMessages(GetMessagesRequest) returns (GetMessagesResponse);
}

message GetChatRoomRequest {
  string room_id = 1;
  string user_id = 2;
}

message GetChatRoomResponse {
  ChatRoom chat_room = 1;
}

message ChatRoom {
  string id = 1;
  string name = 2;
  string description = 3;
  int32 room_type = 4;  // 1: 1:1, 2: group
  string created_by = 5;
  string created_at = 6;
}

message SendMessageRequest {
  string room_id = 1;
  string user_id = 2;
  string content = 3;
  int32 message_type = 4;
}

message SendMessageResponse {
  ChatMessage message = 1;
}

message ChatMessage {
  string id = 1;
  string room_id = 2;
  string user_id = 3;
  string content = 4;
  int32 message_type = 5;
  string created_at = 6;
}

message ListChatRoomsRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message ListChatRoomsResponse {
  repeated ChatRoom chat_rooms = 1;
  int32 total_count = 2;
}

message GetMessagesRequest {
  string room_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}

message GetMessagesResponse {
  repeated ChatMessage messages = 1;
  int32 total_count = 2;
}
```

**빌드 명령어** (gradle-skill):
```bash
./gradlew :protobuf:clean :protobuf:build
```

