### 4. GraphQL 모듈의 Chat 관련 스키마

**`/graphql/` 모듈 구조** (graphql-skill 기반)

```
graphql/
├── src/main/
│   ├── kotlin/com/maum/backend/
│   │   ├── controller/
│   │   │   └── ChatController.kt
│   │   └── service/
│   │       └── ChatService.kt
│   └── resources/graphql/
│       └── chat.graphqls
└── build.gradle.kts
```

**예상 GraphQL 스키마** (graphql-skill 가이드 기반):

```graphql
# graphql/src/main/resources/graphql/chat.graphqls

type ChatRoom {
  id: ID!
  name: String!
  description: String
  roomType: Int!
  createdBy: SimpleUser
  lastMessage: ChatMessage
  createdAt: String!
  updatedAt: String!
}

type ChatMessage {
  id: ID!
  chatRoom: ChatRoom
  user: SimpleUser
  content: String!
  messageType: Int!
  createdAt: String!
}

type ChatRoomWithMessages {
  id: ID!
  name: String!
  messages(limit: Int, offset: Int): [ChatMessage!]!
  participants: [SimpleUser!]!
}

input CreateChatRoomInput {
  name: String!
  description: String
  roomType: Int!
  participantIds: [String!]
}

input SendMessageInput {
  roomId: String!
  content: String!
  messageType: Int!
}

extend type Query {
  chatRoom(id: ID!): ChatRoom
  chatRooms(limit: Int, offset: Int): [ChatRoom!]!
  chatMessages(roomId: ID!, limit: Int, offset: Int): [ChatMessage!]!
}

extend type Mutation {
  createChatRoom(input: CreateChatRoomInput!): ChatRoom!
  sendMessage(input: SendMessageInput!): ChatMessage!
  deleteChatRoom(id: ID!): Boolean!
  leaveChatRoom(roomId: ID!): Boolean!
}
```

**GraphQL Controller** (graphql-skill 가이드):

```kotlin
// graphql/src/main/kotlin/com/maum/backend/controller/ChatController.kt
@Controller
class ChatController(
    private val chatService: ChatService,
    private val userService: UserService,
) {
    @QueryMapping
    @PreAuthorize("hasAuthority('User')")
    fun chatRooms(
        @UserId userId: String,
        @Argument limit: Int?,
        @Argument offset: Int?,
    ): List<ChatRoomResponse> {
        val response = chatService.listChatRooms(userId, limit ?: 20, offset ?: 0)
        return response.chatRoomsList.map { it.toResponse() }
    }

    @MutationMapping
    @PreAuthorize("hasAuthority('User')")
    fun sendMessage(
        @UserId userId: String,
        @Argument input: SendMessageInput,
    ): ChatMessageResponse {
        val response = chatService.sendMessage(userId, input.roomId, input.content)
        return response.message.toResponse()
    }
}
```

**GraphQL Service** (gRPC 클라이언트):

```kotlin
// graphql/src/main/kotlin/com/maum/backend/service/ChatService.kt
@Service
class ChatService {
    @GrpcClient("chat-grpc")
    private lateinit var stub: ChatServiceGrpc.ChatServiceBlockingStub

    fun listChatRooms(userId: String, limit: Int, offset: Int): ListChatRoomsResponse {
        val request = ListChatRoomsRequest.newBuilder()
            .setUserId(userId)
            .setLimit(limit)
            .setOffset(offset)
            .build()
        return try {
            stub.listChatRooms(request)
        } catch (e: StatusRuntimeException) {
            throw CustomGraphQLException(e.trailers!!, e.status.description)
        }
    }
}
```

