### 7. 테스트 구조 (test-skill 기반)

```kotlin
// chat/src/test/kotlin/com/maum/backend/service/ChatMessageServiceTest.kt
@ExtendWith(MockitoExtension::class)
class ChatMessageServiceTest {

    @Mock
    private lateinit var messageRepository: ChatMessageRepository

    @Mock
    private lateinit var roomRepository: ChatRoomRepository

    @InjectMocks
    private lateinit var service: ChatMessageService

    @Test
    fun `should send message successfully`() {
        // given
        val roomId = "room-1"
        val userId = "user-1"
        val content = "Hello"

        // when
        val result = service.sendMessage(userId, roomId, content)

        // then
        assertThat(result.content).isEqualTo(content)
        verify(messageRepository).save(any())
    }
}
```

